import pymongo

# Connect to the MongoDB instance
client = pymongo.MongoClient("mongodb://localhost:27017/")

# Select a database and collection
db = client["mydatabase"]
collection = db["mycollection"]

def execute_filter(filter_expr, filter_params):
    # Create a cursor object that executes the server-side JavaScript expression
    cursor = collection.find({
        "$where": f"function() {{ return {filter_expr}; }}"
    })
    
    try:
        # Pass user-provided parameters to the server-side function
        result = list(cursor.filter(f=lambda doc: filter_params in doc))
        
        # Return the results
        return result
    
    except Exception as e:
        print(f"Error executing JavaScript expression: {str(e)}")
        return []

# Example usage
